}

client/app.js :: readMaxMb
function readMaxMb() {
  const value = Number(document.getElementById("maxMb").value);
  if (!Number.isFinite(value) || value <= 0 || value > 25) {
    throw new Error("Max size must be between 0.1 and 25 MB.");
  }
  return value;
}

client/app.js :: updateFileSelection
function updateFileSelection() {
  const incoming = Array.from(imageInput.files || []);
  if (incoming.length > MAX_FILES) {
    statusEl.textContent = `Only the first ${MAX_FILES} files were kept (limit ${MAX_FILES}).`;
    selectedFiles = incoming.slice(0, MAX_FILES);
    syncInputFiles(selectedFiles);
  } else {
    selectedFiles = incoming;
    if (statusEl.textContent.startsWith("Only the first")) {
      statusEl.textContent = "";
    }
  }

  renderFileList();
  hideFinishPanel();
  updateModeUi();
  syncEditorToSelection();
}

client/app.js :: syncInputFiles
function syncInputFiles(files) {
  const transfer = new DataTransfer();
  for (const file of files) {
    transfer.items.add(file);
  }
  imageInput.files = transfer.files;
}

client/app.js :: renderFileList
function renderFileList() {
  const count = selectedFiles.length;
  fileList.hidden = count === 0;
  clearFilesBtn.hidden = count === 0;

  if (count === 0) {
    fileList.innerHTML = "";
    return;
  }

  fileList.innerHTML = selectedFiles
    .map(
      (file, index) => `
      <li class="file-chip">
        <span class="file-chip-name" title="${escapeHtml(file.name)}">${escapeHtml(file.name)}</span>
        <span class="file-chip-size">${formatBytes(file.size)}</span>
        <button type="button" class="file-chip-remove" data-index="${index}" aria-label="Remove ${escapeHtml(file.name)}">×</button>
      </li>`
    )
    .join("");

  fileList.querySelectorAll(".file-chip-remove").forEach((button) => {
    button.addEventListener("click", () => removeFile(Number(button.dataset.index)));
  });
}

client/app.js :: removeFile
function removeFile(index) {
  selectedFiles = selectedFiles.filter((_, i) => i !== index);
  syncInputFiles(selectedFiles);
  renderFileList();
  updateModeUi();
  syncEditorToSelection();
}

client/app.js :: hideFinishPanel
function hideFinishPanel() {
  if (previewObjectUrl) {
    URL.revokeObjectURL(previewObjectUrl);
    previewObjectUrl = null;
  }
  compressedResult = null;
  finishPanel.hidden = true;
  resultPreview.removeAttribute("src");
  postFilterSelect.value = "none";
}

client/app.js :: showFinishPanel
function showFinishPanel(blob, format, maxMb, baseName, mime) {
  hideFinishPanel();
  compressedResult = { blob, format, maxMb, baseName, mime };
  previewObjectUrl = URL.createObjectURL(blob);
  resultPreview.src = previewObjectUrl;
  finishPanel.hidden = false;
  finishPanel.scrollIntoView({ behavior: "smooth", block: "nearest" });
}

client/app.js :: readPostFilterLabel
function readPostFilterLabel(value) {
  const labels = {
    none: "none",
    blur: "soft blur",
    blur_strong: "strong blur",
    sharpen: "sharpen",
    sharpen_strong: "strong sharpen",
  };
  return labels[value] || value;
}

