async function inspectSelectedFile() {
  const file = selectedFiles[0];
  if (!file) return;

  const formData = new FormData();
  formData.append("image", file);
  inspectBtn.disabled = true;
  statusEl.textContent = "Reading metadata…";
  analyzePanel.hidden = true;

  try {
    const response = await fetch(`${API_BASE}/analyze`, { method: "POST", body: formData });
    const body = await response.json().catch(() => ({}));
    if (!response.ok) {
      throw new Error(body.error || body.detail || "Analyze failed.");
    }
    analyzePanel.textContent = JSON.stringify(body, null, 2);
    analyzePanel.hidden = false;
    const exif = body.exif;
    const exifNote =
      exif?.present ? ` · EXIF ${exif.orientation_label || exif.orientation || "present"}` : "";
    const colorNote =
      body.dominant_colors?.[0]?.hex ? ` · dominant ${body.dominant_colors[0].hex}` : "";
    statusEl.textContent =
      body.summary ||
      `${body.width}×${body.height} ${body.format.toUpperCase()} · ${formatBytes(body.byte_size)}${exifNote}${colorNote}`;
  } catch (error) {
    statusEl.textContent = `Error: ${error.message}`;
  } finally {
    inspectBtn.disabled = false;
  }
}

client/app.js :: updateModeUi
function updateModeUi() {
  const count = selectedFiles.length;

  if (count === 0) {
    modeHint.hidden = true;
    inspectBtn.hidden = true;
    analyzePanel.hidden = true;
    hideFinishPanel();
    processBtn.disabled = true;
    processBtn.textContent = "Select images to start";
    return;
  }

  processBtn.disabled = false;
  modeHint.hidden = false;
  inspectBtn.hidden = count !== 1;

  if (count === 1) {
    modeHint.textContent = "Single image — compress first, then blur/sharpen and download.";
    modeHint.dataset.mode = "single";
    processBtn.textContent = "Compress";
  } else {
    hideFinishPanel();
    modeHint.textContent = `${count} images — batch compresses in the queue; pick any result below to finish and download.`;
    modeHint.dataset.mode = "batch";
    processBtn.textContent = `Process ${count} images`;
  }
}

client/app.js :: processSelection
async function processSelection() {
  const count = selectedFiles.length;
  if (count === 0) {
    statusEl.textContent = "Choose at least one image.";
    return;
  }

  if (count === 1) {
    await convertSingle(selectedFiles[0]);
  } else {
    await submitBatch(selectedFiles);
  }
}

