client/app.js :: refreshQueue
async function refreshQueue(showError) {
  try {
    const response = await fetch(`${API_BASE}/batch`);
    if (!response.ok) {
      throw new Error("Could not load queue.");
    }
    const payload = await response.json();
    renderQueue(payload.jobs || []);
    schedulePolling(payload.jobs || []);
  } catch (error) {
    queueSummary.textContent = showError ? `Error: ${error.message}` : "Queue unavailable.";
    queueList.innerHTML = "";
    queueLive.hidden = true;
  }
}

client/app.js :: schedulePolling
function schedulePolling(jobs) {
  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }

  const hasActive = (jobs || []).some((job) => ACTIVE_STATUSES.has(job.status));
  queueLive.hidden = !hasActive;

  if (hasActive) {
    pollTimer = setInterval(() => refreshQueue(false), POLL_MS);
  }
}

