client/app.js :: collectCompletedBatchItems
function collectCompletedBatchItems(jobs) {
  const entries = [];
  for (const job of jobs) {
    if (job.format === "pdf") continue;
    const shortId = job.id.slice(0, 8);
    for (const item of job.items || []) {
      if (item.status !== "completed") continue;
      entries.push({
        key: `${job.id}:${item.id}`,
        jobId: job.id,
        itemId: item.id,
        label: `${shortId} · ${item.source_name}`,
        sourceName: item.source_name,
        format: job.format,
        maxMb: job.max_mb ?? 1,
      });
    }
  }
  return entries;
}

client/app.js :: updateBatchImagePicker
function updateBatchImagePicker(jobs) {
  const previous = batchImageSelect.value;
  batchFinishSources = collectCompletedBatchItems(jobs);
  batchFinishPicker.hidden = batchFinishSources.length === 0;

  if (batchFinishSources.length === 0) {
    batchImageSelect.innerHTML = '<option value="">No compressed images yet</option>';
    return;
  }

  batchImageSelect.innerHTML =
    '<option value="">Select an image…</option>' +
    batchFinishSources
      .map(
        (entry) =>
          `<option value="${escapeHtml(entry.key)}">${escapeHtml(entry.label)}</option>`
      )
      .join("");

  if (previous && batchFinishSources.some((entry) => entry.key === previous)) {
    batchImageSelect.value = previous;
  }
}

