async function loadBatchItemByKey(key) {
  const entry = batchFinishSources.find((item) => item.key === key);
  if (!entry) return;

  batchImageSelect.value = key;
  statusEl.textContent = `Loading ${entry.sourceName}…`;

  try {
    const response = await fetch(`${API_BASE}/batch/${entry.jobId}/items/${entry.itemId}`);
    if (!response.ok) {
      const error = await response.json().catch(() => ({}));
      throw new Error(error.detail || "Could not load compressed image.");
    }
    const blob = await response.blob();
    const baseName = entry.sourceName.replace(/\.[^.]+$/, "") || "converted";
    const mime = response.headers.get("content-type") || "application/octet-stream";
    const mb = (blob.size / (1024 * 1024)).toFixed(2);
    showFinishPanel(blob, entry.format, entry.maxMb, baseName, mime);
    statusEl.textContent = `Loaded ${entry.sourceName} — ${mb} MB. Choose a finish filter, then download.`;
  } catch (error) {
    statusEl.textContent = `Error: ${error.message}`;
  }
}

