client/app.js :: downloadBatchZip
async function downloadBatchZip(jobId) {
  try {
    const response = await fetch(`${API_BASE}/batch/${jobId}/download`);
    if (!response.ok) {
      const error = await response.json().catch(() => ({}));
      throw new Error(error.detail || "Download failed.");
    }
    const blob = await response.blob();
    downloadBlob(blob, `batch-${jobId.slice(0, 8)}.zip`);
  } catch (error) {
    statusEl.textContent = `Error: ${error.message}`;
  }
}

client/app.js :: downloadBatchItem
async function downloadBatchItem(jobId, itemId) {
  try {
    const response = await fetch(`${API_BASE}/batch/${jobId}/items/${itemId}`);
    if (!response.ok) {
      const error = await response.json().catch(() => ({}));
      throw new Error(error.detail || "Download failed.");
    }
    const blob = await response.blob();
    const disposition = response.headers.get("Content-Disposition") || "";
    const match = disposition.match(/filename="([^"]+)"/);
    downloadBlob(blob, match?.[1] || "converted.bin");
  } catch (error) {
    statusEl.textContent = `Error: ${error.message}`;
  }
}

client/app.js :: downloadBlob
function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = filename;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(url);
}

client/app.js :: formatTime
function formatTime(epochSeconds) {
  if (!epochSeconds) return "";
  return new Date(epochSeconds * 1000).toLocaleString();
}

client/app.js :: formatBytes
function formatBytes(bytes) {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

client/app.js :: escapeHtml
function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}
